# Check the foot slab thickness and whether it's solid between Z=0 and Z=0.8
# Also check the inner face at Z=0.8 to understand what's above
body = rootComp.bRepBodies.itemByName("LED_Stand")

# Get all planar faces at Z=0.8 (the "ceiling" of the foot slab)
ceiling_face = None
bottom_face = None
for i in range(body.faces.count):
    face = body.faces.item(i)
    bb = face.boundingBox
    if face.geometry.surfaceType == adsk.core.SurfaceTypes.PlaneSurfaceType:
        zmin = bb.minPoint.z
        zmax = bb.maxPoint.z
        if abs(zmin - 0.8) < 0.01 and abs(zmax - 0.8) < 0.01:
            if face.area > 200:
                ceiling_face = {
                    'index': i,
                    'area': face.area,
                    'xmin': bb.minPoint.x, 'xmax': bb.maxPoint.x,
                    'ymin': bb.minPoint.y, 'ymax': bb.maxPoint.y
                }
        if abs(zmin - 0.0) < 0.01 and abs(zmax - 0.0) < 0.01:
            if face.area > 200:
                bottom_face = {
                    'index': i,
                    'area': face.area,
                    'xmin': bb.minPoint.x, 'xmax': bb.maxPoint.x,
                    'ymin': bb.minPoint.y, 'ymax': bb.maxPoint.y
                }

result = {'ceiling_face': ceiling_face, 'bottom_face': bottom_face, 
          'slab_thickness_cm': 0.8,
          'note': 'Foot slab goes from Z=0 to Z=0.8 (8mm thick). Inner ceiling at Z=0.8 area covers the full footprint minus any ribs/walls above.'}
